/* Parse a CPC symbol like "H01L 21/768" into components */
CPC.parse = function(symbol) {
  if (!symbol || typeof symbol !== 'string') return null;
  var s = symbol.replace(/\s+/g, ' ').trim();
  var section = s.charAt(0);
  var cls = s.substring(0, 3);
  var subclass = s.substring(0, 4);
  var mainGroup = null, subGroup = null;
  var slashIdx = s.indexOf('/');
  if (slashIdx > 0) {
    var numPart = s.substring(4).replace(/\s/g, '');
    mainGroup = numPart.split('/')[0];
    subGroup = numPart.split('/')[1] || null;
  }
  return {
    symbol: s,
    section: section,
    sectionTitle: CPC.SECTIONS[section] || '',
    class: cls,
    classTitle: CPC.CLASSES[cls] || '',
    subclass: subclass,
    subclassTitle: CPC.SUBCLASSES[subclass] || '',
    mainGroup: mainGroup,
    subGroup: subGroup,
    full: s
  };
};

/* Get a short human-readable label for a CPC code */
CPC.shortLabel = function(symbol) {
  var p = CPC.parse(symbol);
  if (!p) return symbol;
  return p.subclass + (p.mainGroup ? ' ' + p.mainGroup + '/' + (p.subGroup || '00') : '');
};

/* Get section color for visualization */
CPC.sectionColor = function(section) {
  var colors = {
    'A': '#22C55E', 'B': '#3B82F6', 'C': '#D4A017',
    'D': '#8B5CF6', 'E': '#F59E0B', 'F': '#EF4444',
    'G': '#06B6D4', 'H': '#2563EB', 'Y': '#10B981'
  };
  return colors[section] || '#94A3B8';
};

/* Lookup any level */
CPC.lookup = function(code) {
  if (!code) return '';
  if (code.length === 1) return CPC.SECTIONS[code] || '';
  if (code.length === 3) return CPC.CLASSES[code] || '';
  if (code.length === 4) return CPC.SUBCLASSES[code] || '';
  var p = CPC.parse(code);
  return p ? p.subclassTitle : '';
};

window.CPC = CPC;
